export const COASTER_DETAILS: Record<string, CoasterDetailData> = {
  'kingda-ka': {"description":"Kingda Ka was a hydraulically-launched steel roller coaster located at Six Flags Great Adventure in Jackson, New Jersey, United States.  Manufactured by Intamin and designed by Werner Stengel, Kingda Ka opened as the in the world on May 21, 2005, surpassing Top Thrill Dragster.  Although both featured similar designs, Kingda Ka's layout added an airtime hill on the return portion of the track.","wikiUrl":"https://en.wikipedia.org/wiki/Kingda_Ka"},
  'top-thrill-2': {"description":"Top Thrill 2 is a launched roller coaster located at Cedar Point in Sandusky, Ohio, United States.  The ride originally opened as Top Thrill Dragster in 2003, becoming the tallest and fastest roller coaster in the world, as well as the first ever strata coaster.  The original was an Accelerator Coaster model from Intamin designed by Werner Stengel, featuring a height of 420 ft and a drop distance of 400 ft.","wikiUrl":"https://en.wikipedia.org/wiki/Top_Thrill_2","formerNames":["Top Thrill Dragster"]},
  'superman-escape-from-krypton': {"description":"Superman: Escape from Krypton, originally known as Superman: The Escape, was a steel shuttle roller coaster located at Six Flags Magic Mountain in Valencia, California.  At the time of its opening in 1997, it was the tallest roller coaster in the world, a title which it lost to Top Thrill Dragster in 2003.  Its maximum speed of 100 mph was tied for the fastest with Tower of Terror II, a similar roller coaster which opened two months earlier at Dreamworld in Australia.","wikiUrl":"https://en.wikipedia.org/wiki/Superman%3A_Escape_from_Krypton","formerNames":["Superman: The Escape"]},
  'millennium-force': {"description":"Millennium Force is a steel roller coaster located at Cedar Point amusement park in Sandusky, Ohio, United States.  Manufactured by Intamin, it was the park's fourteenth roller coaster when it opened in 2000, dating back to the opening of Blue Streak in 1964.  Upon completion, Millennium Force broke five world records and was the world's first giga coaster, a term coined by Intamin and Cedar Point to represent a roller coaster that exceeds 300 ft in height.","wikiUrl":"https://en.wikipedia.org/wiki/Millennium_Force"},
  'steel-vengeance': {"description":"Steel Vengeance is a steel roller coaster located at Cedar Point in Sandusky, Ohio, United States.  It was formerly known as Mean Streak, a wooden coaster constructed by Dinn Corporation that opened in 1991 as the tallest wooden coaster in the world.  Rocky Mountain Construction (RMC) was hired to remake the ride into a hybrid coaster, combining their steel I-Box track with a significant portion of Mean Streak's wooden structure.","wikiUrl":"https://en.wikipedia.org/wiki/Steel_Vengeance","formerNames":["Mean Streak"]},
  'x2': {"description":"X2 (formerly known as X) is a steel roller coaster at Six Flags Magic Mountain in Valencia, California.  It was the world's first fourth-dimension roller coaster and was the final roller coaster installed by ride manufacturer Arrow Dynamics.  The ride is unique in that the trains' seats pitch 360 degrees forwards and in reverse independent of the main chassis.","wikiUrl":"https://en.wikipedia.org/wiki/X2_(roller_coaster)","formerNames":["X"]},
  'son-of-beast': {"description":"Son of Beast was a wooden roller coaster located at Kings Island in Mason, Ohio, United States.  Built and designed by the now-defunct Roller Coaster Corporation of America (RCCA), the ride opened as the tallest and fastest wooden coaster in the world on April 28, 2000.  Its record-setting height of 218 ft made it the first wooden hypercoaster – a height class of 200 ft or more.","wikiUrl":"https://en.wikipedia.org/wiki/Son_of_Beast"},
  'pantherian': {"description":"Pantherian (originally known as Intimidator 305 and temporarily named Project 305 for the 2024 season) is a steel roller coaster located at Kings Dominion in Doswell, Virginia, United States.  The ride was manufactured by Intamin and opened to the public on April 2, 2010.  Originally themed to racing, the coaster was originally named after the late NASCAR driver Dale Earnhardt, who was commonly known as \"The Intimidator\".","wikiUrl":"https://en.wikipedia.org/wiki/Pantherian","formerNames":["Intimidator 305  and Project 305"]},
  'the-beast': {"description":"The Beast is a wooden roller coaster located at Kings Island amusement park in Mason, Ohio, United States.  Designed and manufactured in-house for approximately $3 million, the ride opened in 1979 as the tallest, fastest, and longest wooden roller coaster in the world.  Decades later, it is still the longest, spanning 7361 ft across 35 acre of hilly terrain.","wikiUrl":"https://en.wikipedia.org/wiki/The_Beast_(roller_coaster)"},
  'sirens-curse': {"description":"Siren's Curse is a steel roller coaster located at Cedar Point in Sandusky, Ohio.  The Tilt Coaster model, manufactured by Vekoma, opened to the public on June 28, 2025.  The ride has a length of 2966 ft with a maximum height of 160 ft, a 90-degree drop, and two inversions.","wikiUrl":"https://en.wikipedia.org/wiki/Siren's_Curse"},
  'twisted-colossus': {"description":"Twisted Colossus is a steel roller coaster located at Six Flags Magic Mountain in Valencia, California.  Originally designed and built by International Amusement Devices, the roller coaster opened as Colossus, a dual-tracked roller coaster, on June 29, 1978.  It was the tallest and fastest wooden roller coaster in the world and the first with two drops greater than 100 ft.","wikiUrl":"https://en.wikipedia.org/wiki/Twisted_Colossus","formerNames":["Colossus"]},
  'magnum-xl-200': {"description":"Magnum XL-200, colloquially known as simply Magnum, is a steel roller coaster built by Arrow Dynamics at Cedar Point in Sandusky, Ohio.  When it opened in 1989, it was the tallest, fastest, and steepest complete-circuit roller coaster in the world as well as the first hypercoaster – a roller coaster that exceeds 200 ft in height.  Some have credited Magnum with starting a period in the industry known as the roller coaster wars, in which amusement parks competed with one another at a rapid pace to build the next tallest and fastest roller coaster.","wikiUrl":"https://en.wikipedia.org/wiki/Magnum_XL-200"},
  'leviathan': {"description":"Leviathan is a steel roller coaster located at Canada's Wonderland in Vaughan, Ontario, Canada.  Located in the Medieval Faire section of the park, the Hyper Coaster model from Swiss firm Bolliger & Mabillard is the first roller coaster manufactured by the company to exceed a height of 91. 5 m, putting it in a class of roller coasters commonly referred to as giga.","wikiUrl":"https://en.wikipedia.org/wiki/Leviathan_(Canada's_Wonderland)"},
  'goliath': {"description":"Goliath is a steel roller coaster located at Six Flags Magic Mountain amusement park in Valencia, California.  Manufactured by Giovanola of Switzerland, the hypercoaster is located in the Goliath Plaza section of the park and opened to the public on February 11, 2000.  Its sub-tropical theme is characterized by ancient ruins of the Mayan civilization.","wikiUrl":"https://en.wikipedia.org/wiki/Goliath_(Six_Flags_Magic_Mountain)"},
  'el-toro': {"description":"El Toro (Spanish for The Bull) is a wooden roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  Designed by Werner Stengel and manufactured by Intamin, the ride opened to the public on June 11, 2006.  Intamin subcontracted Rocky Mountain Construction to build the ride, and the coaster's track was prefabricated, allowing for quicker installation and lower construction costs.","wikiUrl":"https://en.wikipedia.org/wiki/El_Toro_(Six_Flags_Great_Adventure)"},
  'valravn': {"description":"Valravn is a steel roller coaster at Cedar Point amusement park in Sandusky, Ohio.  Built and designed by Bolliger & Mabillard (B&M), it was the first Dive Coaster model in the Cedar Fair chain of parks and opened on May 7, 2016, as the tallest, fastest, and longest of its kind in the world.  It remains the tallest, sharing its height record with Yukon Striker at Canada's Wonderland.","wikiUrl":"https://en.wikipedia.org/wiki/Valravn_(roller_coaster)"},
  'formula-rossa': {"description":"Formula Rossa (Arabic: فورمولا روسا) is a launched roller coaster located at Ferrari World in Abu Dhabi, United Arab Emirates.  Manufactured by Intamin, the ride set a speed record when it opened on 4 November 2010, and became the fastest roller coaster in the world upon opening with a maximum speed of 240 km/h.  It surpassed Kingda Ka at Six Flags Great Adventure, which had held the record since 2005.","wikiUrl":"https://en.wikipedia.org/wiki/Formula_Rossa"},
  'steel-curtain': {"description":"Steel Curtain is a steel hypercoaster at Kennywood in West Mifflin, Pennsylvania, United States.  Manufactured by S&S – Sansei Technologies, the coaster reaches a height of 220 ft and features either eight or nine inversions, including a 197 ft corkscrew which was the world's tallest inversion at the time.  Themed to the Pittsburgh Steelers NFL football team, the roller coaster is named after the Steel Curtain, the nickname for the Steelers' defensive line during the 1970s.","wikiUrl":"https://en.wikipedia.org/wiki/Steel_Curtain_(roller_coaster)"},
  'gatekeeper': {"description":"GateKeeper is a steel roller coaster located at Cedar Point amusement park in Sandusky, Ohio.  Designed by Bolliger & Mabillard (B&M), it was the fifth Wing Coaster installation in the world.  The ride opened on May 11, 2013, on the most successful opening weekend to date in the park's history.","wikiUrl":"https://en.wikipedia.org/wiki/GateKeeper_(roller_coaster)"},
  'jurassic-world-velocicoaster': {"description":"Jurassic World VelociCoaster is a launched roller coaster at Universal Islands of Adventure in Orlando, Florida.  Manufactured by Intamin, the ride opened to the public on June 10, 2021.  It is themed to the Velociraptor dinosaurs depicted in the Jurassic World film franchise and is located in the Islands of Adventure's Jurassic Park area, occupying the site of the former Triceratops Encounter attraction.","wikiUrl":"https://en.wikipedia.org/wiki/VelociCoaster"},
  'maverick': {"description":"Maverick is a steel roller coaster located at Cedar Point in Sandusky, Ohio.  Manufactured by Intamin at a cost of $21 million, it was the 500th roller coaster designed by German engineer Werner Stengel and the first to feature a twisted horseshoe roll element.  There are two launch points along the 4450 ft track that utilize linear synchronous motors (LSM).","wikiUrl":"https://en.wikipedia.org/wiki/Maverick_(roller_coaster)"},
  'green-lantern': {"description":"Green Lantern, formerly known as Chang, was a stand-up roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  It stood 155 ft tall and featured a top speed of 63 mph.  The 4155 ft ride featured five inversions and had a duration of approximately 21/2 minutes.","wikiUrl":"https://en.wikipedia.org/wiki/Green_Lantern_(Six_Flags_Great_Adventure)","formerNames":["Chang  at Six Flags Kentucky Kingdom"]},
  'steel-dragon-2000': {"description":"Steel Dragon 2000 (スチールドラゴン2000) is a steel roller coaster located at Nagashima Spa Land amusement park in Mie Prefecture, Japan. \n\nBuilt by D.  H.","wikiUrl":"https://en.wikipedia.org/wiki/Steel_Dragon_2000"},
  'the-smiler': {"description":"The Smiler is a steel roller coaster located at Alton Towers Resort in Staffordshire, United Kingdom.  It was built in 2013 and is an Infinity Coaster model from Gerstlauer and is located in the X-Sector area of the park.  The ride currently holds a world record for most inversions on a roller coaster, featuring 14 inversions that include dive loops, sidewinders, corkscrews, and other inverting elements.","wikiUrl":"https://en.wikipedia.org/wiki/The_Smiler"},
  'tatsu': {"description":"Tatsu is a flying roller coaster designed by Bolliger & Mabillard at the Six Flags Magic Mountain amusement park located in Valencia, California, United States.  Manufactured by Bolliger & Mabillard, it opened as the tallest, fastest, and longest flying coaster in the world on May 13, 2006.  It became the park's seventeenth coaster, featuring a height of 170 ft, a track length of 3602 ft, and a maximum speed of 62 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Tatsu"},
  'xcelerator': {"description":"Xcelerator is a steel launched roller coaster located at Knott's Berry Farm in Buena Park, California, United States.  Manufactured by Intamin and designed by Werner Stengel, it opened in 2002 as the company's first hydraulically-launched coaster and cost $13 million to construct.  Following the early demise of Windjammer Surf Racers, a dueling roller coaster that briefly operated from 1997 to 2000, Xcelerator was soon announced as its replacement.","wikiUrl":"https://en.wikipedia.org/wiki/Xcelerator"},
  'banshee': {"description":"Banshee is an inverted roller coaster located at Kings Island amusement park in Mason, Ohio, United States.  Designed and manufactured by Swiss company Bolliger & Mabillard, the ride opened to the public on April 18, 2014, and is the longest inverted coaster in the world, featuring a track length of 4124 ft.  Banshee was also the most expensive project in Kings Island's history at the time, costing the park $24 million to construct.","wikiUrl":"https://en.wikipedia.org/wiki/Banshee_(roller_coaster)"},
  'yukon-striker': {"description":"Yukon Striker is a steel roller coaster at Canada's Wonderland in Vaughan, Ontario.  Designed as a Dive Coaster from manufacturer Bolliger & Mabillard, the ride opened to the general public on 3 May 2019 in place of SkyRider, a roller coaster that was removed from the park in 2014.  Featuring a height of 68 m, a length of 1105 m, and a maximum speed of 130 km/h, Yukon Striker is the world's tallest, longest, and fastest dive coaster, sharing its height record with Valravn at Cedar Point.","wikiUrl":"https://en.wikipedia.org/wiki/Yukon_Striker"},
  'phantoms-revenge': {"description":"Phantom's Revenge is a steel hypercoaster located at Kennywood in West Mifflin, Pennsylvania.  It originally opened as Steel Phantom in 1991, featuring the fastest speed and longest drop of any roller coaster in the world at the time.  Its second drop is longer than its first, which is a unique characteristic among roller coasters.","wikiUrl":"https://en.wikipedia.org/wiki/Phantom's_Revenge","formerNames":["Steel Phantom"]},
  'hollywood-rip-ride-rockit': {"description":"Hollywood Rip Ride Rockit was a steel roller coaster located at Universal Studios Florida in Orlando, Florida, United States.  With a height of 167 ft and a length of 3800 ft, it opened on August 19, 2009, as the largest X-Car model coaster ever built by German manufacturer Maurer Söhne.  The roller coaster reached a maximum speed of 65 mph and featured on-ride music that riders could select when boarding, as well as individual on-ride cameras that captured video of each passenger.","wikiUrl":"https://en.wikipedia.org/wiki/Hollywood_Rip_Ride_Rockit"},
  'hyperia': {"description":"Hyperia is a steel roller coaster located at Thorpe Park in Chertsey, Surrey, England.  Manufactured by Mack Rides, the hypercoaster opened as the tallest and fastest roller coaster in the United Kingdom on 24 May 2024, with a height of 236 ft and a maximum speed that reaches 81 mph.  It also features two inversions and was built on the site formerly occupied by Loggers Leap and Rocky Express.","wikiUrl":"https://en.wikipedia.org/wiki/Hyperia_(roller_coaster)"},
  'flight-of-fear': {"description":"Flight of Fear is the name of two identical enclosed roller coasters located at Kings Island and Kings Dominion amusement parks.  Built and designed by Premier Rides, they were the world's first launched roller coasters to feature linear induction motor (LIM) technology.  Both locations opened as The Outer Limits: Flight of Fear on June 18, 1996, originally themed after The Outer Limits TV series that began airing in 1995 as a revival of the original 1960s series.","wikiUrl":"https://en.wikipedia.org/wiki/Flight_of_Fear","formerNames":["The Outer Limits: Flight of Fear"]},
  'nemesis-reborn': {"description":"Nemesis Reborn, previously Nemesis, is an inverted roller coaster located at the Alton Towers theme park in Staffordshire, England.  It was manufactured by Bolliger & Mabillard (B&M) and designed by Werner Stengel, from a concept by park developer John Wardley.  It opened in the Forbidden Valley (formerly Thunder Valley) area of the park on 19 March 1994.","wikiUrl":"https://en.wikipedia.org/wiki/Nemesis_Reborn","formerNames":["Nemesis"]},
  'hyperion': {"description":"Hyperion is a steel roller coaster located at Energylandia in Zator, Poland.  The ride was manufactured by Swiss manufacturer Intamin and opened on 14 July 2018.  It is themed to a fictional mission to Saturn's moon Hyperion and reaches a height of 77 m, has a maximum speed of 142 km/h, and features several hills and banked turns.","wikiUrl":"https://en.wikipedia.org/wiki/Hyperion_(roller_coaster)"},
  'oblivion': {"description":"Oblivion is a steel roller coaster at the Alton Towers theme park in Staffordshire, England.  Marketed as the \"world's first vertical drop roller coaster\", it was manufactured by Bolliger & Mabillard as the first Dive Coaster. \n\nOblivion was constructed for a price of £12 million (equivalent to £ million in ) beginning in 1997.","wikiUrl":"https://en.wikipedia.org/wiki/Oblivion_(roller_coaster)"},
  'rougarou': {"description":"Rougarou, formerly known as Mantis, is a floorless roller coaster located at Cedar Point amusement park in Sandusky, Ohio.  Designed and built by Bolliger & Mabillard, the roller coaster originally opened in 1996 as a stand-up roller coaster called Mantis, which at the time was the tallest, fastest, and longest of its kind in the world.  Cedar Point had planned to name the ride Banshee, but due to negative publicity following the announcement, the name was later changed to Mantis.","wikiUrl":"https://en.wikipedia.org/wiki/Rougarou_(roller_coaster)","formerNames":["Mantis"]},
  'nitro': {"description":"Nitro is a steel roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  Manufactured by Bolliger & Mabillard, the Hyper Coaster model opened to the public on April 7, 2001.  Since its debut, Nitro has consistently ranked high among steel coasters in the annual Golden Ticket Awards from Amusement Today, peaking in third place during its tenure.","wikiUrl":"https://en.wikipedia.org/wiki/Nitro_(Six_Flags_Great_Adventure)"},
  'viper': {"description":"Viper is a steel roller coaster located in the Baja Ridge area of Six Flags Magic Mountain in Valencia, California.  Viper is the last operating roller coaster with seven inversions to be built by American manufacturer Arrow Dynamics.  The other two, Shockwave at Six Flags Great America and the Great American Scream Machine at Six Flags Great Adventure, were demolished in 2002 and 2010, respectively.","wikiUrl":"https://en.wikipedia.org/wiki/Viper_(Six_Flags_Magic_Mountain)"},
  'full-throttle': {"description":"Full Throttle is a launched roller coaster located in Six Flags Plaza at Six Flags Magic Mountain in Valencia, California.  Designed and manufactured by Premier Rides, the ride opened to the public on June 22, 2013.  It featured the world's tallest vertical loop of 160 ft when it opened, a record that was surpassed in 2016 by Flash at Lewa Adventure in Xianyang, China.","wikiUrl":"https://en.wikipedia.org/wiki/Full_Throttle_(roller_coaster)"},
  'goliath-six-flags-new-england': {"description":"Goliath was a steel shuttle roller coaster located at Six Flags New England in Agawam, Massachusetts.  Manufactured by Vekoma, the ride originally opened as Déjà Vu at Six Flags Magic Mountain in 2001.  The ride was a larger, inverted version of Vekoma's popular Boomerang sit-down roller coasters.","wikiUrl":"https://en.wikipedia.org/wiki/Goliath_(Six_Flags_New_England)","formerNames":["Déjà Vu at Six Flags Magic Mountain"]},
  'big-thunder-mountain-railroad': {"description":"Big Thunder Mountain Railroad is a mine train roller coaster located at Disneyland, Magic Kingdom in Disney World, Tokyo Disneyland and Disneyland Park (Paris).  In Tokyo and Paris, the attraction is named Big Thunder Mountain.  Big Thunder Mountain Railroad is also the name of the fictional rail line the roller coaster depicts.","wikiUrl":"https://en.wikipedia.org/wiki/Big_Thunder_Mountain_Railroad"},
  'great-american-scream-machine-six-flags-great-adventure': {"description":"Great American Scream Machine was a steel roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  The 173 ft ride opened in 1989 as the tallest and fastest looping roller coaster in the world, reaching a maximum speed of 68 mph.  It was designed by Ron Toomer and manufactured by Arrow Dynamics, which built two other coasters with similar layouts – Shockwave at Six Flags Great America and Viper at Six Flags Magic Mountain.","wikiUrl":"https://en.wikipedia.org/wiki/Great_American_Scream_Machine_(Six_Flags_Great_Adventure)"},
  'the-riddlers-revenge': {"description":"The Riddler's Revenge is a steel stand-up roller coaster located at Six Flags Magic Mountain.  Manufactured by Bolliger & Mabillard, the ride opened as the park's eleventh roller coaster on April 4, 1998, setting multiple world records among stand-up coasters.  Originally located in the Movie District section of the park, which later became Metropolis in 2017, The Riddler's Revenge was also the park's single biggest investment at a cost of $14 million.","wikiUrl":"https://en.wikipedia.org/wiki/The_Riddler's_Revenge"},
  'mr-freeze': {"description":"Mr.  Freeze is a launched shuttle roller coaster located at Six Flags Over Texas in Arlington, Texas, with another installation known as Mr.  Freeze: Reverse Blast at Six Flags St.","wikiUrl":"https://en.wikipedia.org/wiki/Mr._Freeze_(roller_coaster)","formerNames":["Mr. Freeze  Mr. Freeze Reverse Blast"]},
  'tower-of-terror-ii': {"description":"The Tower of Terror II was a steel shuttle roller coaster located at the Dreamworld amusement park on the Gold Coast, Queensland, Australia.  When the Tower of Terror opened on 23 January 1997, it was the first roller coaster in the world to reach 100 mph, making it the tallest and fastest roller coaster in the world of its time.  The ride was situated on the Dreamworld Tower, which also houses The Giant Drop free fall ride.","wikiUrl":"https://en.wikipedia.org/wiki/Tower_of_Terror_II","formerNames":["Tower of Terror"]},
  'wicked-twister': {"description":"Wicked Twister was an inverted roller coaster located at Cedar Point amusement park in Sandusky, Ohio, United States.  Designed by Werner Stengel, it was a second-generation, double-twisting Impulse model manufactured by Intamin.  Wicked Twister opened as the tallest and fastest inverted coaster in the world on May 5, 2002.","wikiUrl":"https://en.wikipedia.org/wiki/Wicked_Twister"},
  'behemoth': {"description":"Behemoth is a steel roller coaster located at Canada's Wonderland in Vaughan, Ontario.  Designed and developed by Swiss manufacturer Bolliger & Mabillard (B&M), Behemoth opened to the public in May 2008 as the tallest and fastest roller coaster in Canada, a claim it held until 2012 when Leviathan opened at the same park.  Behemoth is similar to Diamondback (Kings Island) and Thunder Striker (Carowinds).","wikiUrl":"https://en.wikipedia.org/wiki/Behemoth_(roller_coaster)"},
  'raptor': {"description":"Raptor is an inverted roller coaster designed by Bolliger & Mabillard at Cedar Point in Sandusky, Ohio, United States.  The coaster, which broke many records upon its opening in 1994, differs from previous inverted coasters.  Instead of having a short layout designed to fit into a compact area like Batman: The Ride, Raptor was designed with a larger, 3,790-foot (1,160 m) layout, making it the tallest, fastest and longest inverted roller coaster in the world when it opened.","wikiUrl":"https://en.wikipedia.org/wiki/Raptor_(Cedar_Point)"},
  'red-force': {"description":"Red Force is a steel launched giga roller coaster located at Ferrari Land within PortAventura World in Salou, Catalonia, Spain.  The ride was manufactured by Liechtenstein-based manufacturer Intamin and opened on 7 April 2017.  With a height of 112 m and a maximum speed of 180.","wikiUrl":"https://en.wikipedia.org/wiki/Red_Force_(roller_coaster)"},
  'wicker-man': {"description":"Wicker Man is a wooden roller coaster at Alton Towers theme park in Staffordshire, United Kingdom.  Manufactured by Great Coasters International, the £16-million ride opened to the public on 20 March 2018 following a three-day weather delay.  It set several milestones among wooden coasters including the first to be built in the UK in 22 years and the first to incorporate fire.","wikiUrl":"https://en.wikipedia.org/wiki/Wicker_Man_(roller_coaster)"},
  'disaster-transport': {"description":"Disaster Transport (originally Avalanche Run) was an enclosed steel bobsled roller coaster built by Intamin at Cedar Point in Sandusky, Ohio, United States.  It was notable as being the only indoor roller coaster at Cedar Point, the only bobsled roller coaster in the Midwestern United States, and the only enclosed bobsled roller coaster in the world at its debut.  The name of the ride stems from a rearrangement of the letters \"Dispatch Master Transport\", which could still be seen in the ride's logo in its later years.","wikiUrl":"https://en.wikipedia.org/wiki/Disaster_Transport","formerNames":["Avalanche Run"]},
  'new-texas-giant': {"description":"New Texas Giant is a steel roller coaster located at Six Flags Over Texas in Arlington, Texas.  It originally opened as Texas Giant, which was the tallest wooden coaster in the world when it debuted in 1990.  Manufactured by Dinn Corporation and designed by Curtis D.","wikiUrl":"https://en.wikipedia.org/wiki/New_Texas_Giant","formerNames":["Texas Giant"]},
  'superman-the-ride': {"description":"Superman The Ride (formerly known as Bizarro and Superman – Ride of Steel) is a steel roller coaster at Six Flags New England in Agawam, Massachusetts.  Built by Liechtensteiner manufacturer Intamin, the hypercoaster opened to the public as Superman – Ride of Steel in 2000.  It features a 208 ft lift hill, a 221 ft drop, and a maximum speed of 77 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Superman_The_Ride","formerNames":["Superman: Ride of Steel","Bizarro"]},
  'thunder-striker': {"description":"Thunder Striker, formerly known as Intimidator, is a hypercoaster located at Carowinds in Charlotte, North Carolina, United States.  Built by Bolliger & Mabillard and located in the Thunder Road section of the park, the ride opened to public on March 27, 2010.  It features a 232 ft lift hill, a top speed of 75 mph, and a track length of 5316 ft.","wikiUrl":"https://en.wikipedia.org/wiki/Thunder_Striker","formerNames":["Intimidator"]},
  'blue-streak': {"description":"Blue Streak  is a wooden roller coaster located at Cedar Point in Sandusky, Ohio, United States.  Built by Philadelphia Toboggan Company, Blue Streak opened to the public on May 23, 1964.  It is the oldest roller coaster operating at Cedar Point.","wikiUrl":"https://en.wikipedia.org/wiki/Blue_Streak_(Cedar_Point)"},
  'firehawk': {"description":"Firehawk was a flying roller coaster located at Kings Island in Mason, Ohio.  Manufactured by Vekoma, it originally opened as X-Flight at Six Flags Worlds of Adventure on May 26, 2001, billed as the Midwest's first and only flying roller coaster.  Cedar Fair purchased Worlds of Adventure in 2004 and began efforts to downsize the park.","wikiUrl":"https://en.wikipedia.org/wiki/Firehawk_(roller_coaster)","formerNames":["X-Flight at Six Flags Worlds of Adventure/Geauga Lake"]},
  'sheikra': {"description":"SheiKra is a steel Dive Coaster roller coaster at the Busch Gardens Tampa Bay amusement park in Tampa, Florida, United States.  The roller coaster was proposed by Mark Rose, vice-president of design and engineering for the park, and designed by Bolliger & Mabillard.  The ride was planned to be 160 ft high, but the park's executives rejected this and the height was changed to 200 ft.","wikiUrl":"https://en.wikipedia.org/wiki/SheiKra"},
  'skyrush': {"description":"Skyrush is an Intamin prototype Wing Coaster at Hersheypark in Hershey, Pennsylvania, United States.  It opened to the general public on May 26, 2012, as Hersheypark's 12th roller coaster and the park's third coaster made by Intamin.  Skyrush features a 200 ft cable lift that raises the train at 26 ft/sec.","wikiUrl":"https://en.wikipedia.org/wiki/Skyrush"},
  'wildcats-revenge': {"description":"Wildcat's Revenge is a hybrid roller coaster located at Hersheypark in Hershey, Pennsylvania, United States.  The ride originally opened in 1996 as Wildcat, a wooden coaster manufactured by Great Coasters International (GCI).  The wooden coaster was the first from GCI and served as the anchor attraction of the Midway America section of the park.","wikiUrl":"https://en.wikipedia.org/wiki/Wildcat's_Revenge","formerNames":["Wildcat"]},
  'wrath-of-rakshasa': {"description":"Wrath of Rakshasa (pronounced ; ) is a steel roller coaster located at Six Flags Great America in Gurnee, Illinois, United States.  Manufactured by Bolliger & Mabillard, the Dive Coaster model opened to the public on May 31, 2025.  The roller coaster reaches a height of 180 ft, a maximum vertical angle of 96°, a maximum speed of 67 mph, and features five total inversions.","wikiUrl":"https://en.wikipedia.org/wiki/Wrath_of_Rakshasa"},
  'raging-bull': {"description":"Raging Bull is a steel roller coaster located at Six Flags Great America in Gurnee, Illinois, United States.  The ride opened to the public on May 1, 1999, as the first hyper-twister roller coaster, the second Hyper Coaster model built by Bolliger & Mabillard, and the tallest and longest coaster in the park. \n\nThe 5057 ft ride is themed to a bull and is located in the park's Southwest Territory land.","wikiUrl":"https://en.wikipedia.org/wiki/Raging_Bull_(roller_coaster)"},
  'green-lantern-first-flight': {"description":"Green Lantern: First Flight was a steel roller coaster formerly located at Six Flags Magic Mountain in Valencia, California, United States.  The ZacSpin model from Intamin was the first of its kind in the US when it opened on July 1, 2011.  Its debut allowed Magic Mountain to reclaim its status of having the most roller coasters in the world.","wikiUrl":"https://en.wikipedia.org/wiki/Green_Lantern%3A_First_Flight_(roller_coaster)"},
  'titan': {"description":"Titan is a steel roller coaster located at Six Flags Over Texas in Arlington, Texas.  Built by Giovanola and designed by Werner Stengel, the 245 ft hypercoaster features an out and back and twister track layout, a 255 ft drop, and a maximum speed of 85 mph.  Titan opened as the tallest, fastest, and longest roller coaster in Texas.","wikiUrl":"https://en.wikipedia.org/wiki/Titan_(Six_Flags_Over_Texas)"},
  'diamondback': {"description":"Diamondback is a steel roller coaster located at Kings Island in Mason, Ohio, United States.  Manufactured by Bolliger & Mabillard (B&M), the ride opened in 2009 as the first hypercoaster to feature a splashdown effect and the first B&M roller coaster at Kings Island.  It is located in Rivertown just behind International Street and the Eiffel Tower.","wikiUrl":"https://en.wikipedia.org/wiki/Diamondback_(Kings_Island)"},
  'galactica': {"description":"Galactica is a flying roller coaster located in the Forbidden Valley area of Alton Towers amusement park in Staffordshire, England.  It originally opened as Air on 16 March 2002 and is the first flying coaster manufactured by Bolliger & Mabillard.  Guests ride in a prone position, meant to produce the feeling of flight, as the train passes close to the ground, under footpaths, and narrowly past trees and rocks.","wikiUrl":"https://en.wikipedia.org/wiki/Galactica_(roller_coaster)","formerNames":["Air"]},
  'the-incredible-hulk-coaster': {"description":"The Incredible Hulk Coaster is a launched roller coaster located at Universal Islands of Adventure theme park within the Universal Orlando Resort.  Designed by Werner Stengel and manufactured by Bolliger & Mabillard (B&M), the roller coaster is themed after the Hulk comic book superhero and opened to the public on May 28, 1999.  It is the first B&M coaster themed to a Marvel Comics superhero character and the first to feature a launch design, which was primarily implemented by Universal Creative and MTS Systems Corporation.","wikiUrl":"https://en.wikipedia.org/wiki/The_Incredible_Hulk_Coaster"},
  'medusa-six-flags-great-adventure': {"description":"Medusa, formerly known as Bizarro, is a steel roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  Manufactured by Bolliger & Mabillard, the ride debuted as the world's first floorless roller coaster on April 2, 1999.  It was repainted and rethemed to Bizarro in 2009.","wikiUrl":"https://en.wikipedia.org/wiki/Medusa_(Six_Flags_Great_Adventure)","formerNames":["Bizarro"]},
  'pandemonium': {"description":"Pandemonium is a steel spinning roller coaster designed by Gerstlauer, located at several Six Flags amusement parks in the United States.  Since 2005, Six Flags has installed Pandemonium in five of its parks. \n\nIts design consists of several cars holding four riders each.","wikiUrl":"https://en.wikipedia.org/wiki/Pandemonium_(roller_coaster)"},
  'corkscrew-cedar-point': {"description":"Corkscrew is a steel roller coaster located at Cedar Point in Sandusky, Ohio, United States.  Built by Arrow Development and designed by Ron Toomer, it opened to the public on May 15, 1976.  The coaster features Arrow's first vertical loop and was built during the same time period as The New Revolution at Magic Mountain.","wikiUrl":"https://en.wikipedia.org/wiki/Corkscrew_(Cedar_Point)"},
  'gemini': {"description":"Gemini is a racing roller coaster with a wooden structure and steel track located at Cedar Point in Sandusky, Ohio, United States.  Built in 1978 by Arrow Dynamics and designed by Ron Toomer, it is one of the oldest roller coasters still operating at the park, with only Blue Streak, Cedar Creek Mine Ride, and Corkscrew being older.  Cedar Point marketed the ride as the tallest, fastest, and steepest roller coaster in the world, despite taller and faster coasters that had opened earlier.","wikiUrl":"https://en.wikipedia.org/wiki/Gemini_(roller_coaster)"},
  'iron-gwazi': {"description":"Iron Gwazi (formerly called Gwazi) is a steel-track hybrid roller coaster at Busch Gardens Tampa Bay, a theme park in Tampa, Florida, United States.  The renovated ride opened to the public on March 11, 2022, following a passholder soft-opening a month earlier on February 13.  Development of the original Gwazi began in July 1998, when Busch Gardens announced that it would build a wooden roller coaster on land formerly occupied by the Anheuser-Busch brewery.","wikiUrl":"https://en.wikipedia.org/wiki/Iron_Gwazi","formerNames":["Gwazi"]},
  'vortex-kings-island': {"description":"Vortex was a steel roller coaster located at Kings Island amusement park in Mason, Ohio, United States.  Designed and manufactured by Arrow Dynamics at a cost of $4 million, the ride officially opened to the public on April 11, 1987.  Vortex debuted as the tallest full-circuit roller coaster in the world with a height of 148 ft.","wikiUrl":"https://en.wikipedia.org/wiki/Vortex_(Kings_Island)"},
  'hagrid-s-magical-creatures-motorbike-adventure': {"description":"Hagrid's Magical Creatures Motorbike Adventure is a multiple-launch steel roller coaster located in The Wizarding World of Harry Potter – Hogsmeade section of Universal Islands of Adventure in Orlando, Florida.  Manufactured by Intamin, the attraction opened to the public on June 13, 2019.  The partially-enclosed motorbike coaster operates both indoor and outdoor, and it is the sixth Harry Potter-themed attraction created for the resort.","wikiUrl":"https://en.wikipedia.org/wiki/Hagrid's_Magical_Creatures_Motorbike_Adventure"},
  'scream': {"description":"Scream (originally stylized as Scream! ) is a steel roller coaster at Six Flags Magic Mountain.  Manufactured by Bolliger & Mabillard, the Floorless Coaster model was the park's sixteenth roller coaster and is located in the Screampunk District area of the park.","wikiUrl":"https://en.wikipedia.org/wiki/Scream_(roller_coaster)"},
  'candymonium': {"description":"Candymonium is a steel roller coaster located at Hersheypark in Hershey, Pennsylvania, United States.  Designed by Bolliger & Mabillard, the ride was announced in 2019 and opened on July 3, 2020.  It is the tallest, fastest, and longest roller coaster at Hersheypark.","wikiUrl":"https://en.wikipedia.org/wiki/Candymonium"},
  'incredicoaster': {"description":"Incredicoaster is a steel launched roller coaster located at Disney California Adventure in Anaheim, California, United States.  Manufactured by Intamin, the ride was originally opened to the public as California Screamin' on February 8, 2001.  It is the only roller coaster with an inversion at the Disneyland Resort, in addition to also being the fastest, reaching a maximum speed of 55 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Incredicoaster","formerNames":["California Screamin'"]},
  'mystic-timbers': {"description":"Mystic Timbers is a wooden roller coaster located at Kings Island in Mason, Ohio.  Constructed by Great Coasters International and designed by Skyline Design, the roller coaster opened in the Rivertown section of the park on April 15, 2017.  The ride's fictional theme is set to the site of an abandoned logging company where unexplained events are taking place.","wikiUrl":"https://en.wikipedia.org/wiki/Mystic_Timbers"},
  'the-new-revolution': {"description":"The New Revolution (formerly known as Revolution, Great American Revolution and La Revolución) is a steel roller coaster located at Six Flags Magic Mountain in Valencia, California.  Manufactured by Anton Schwarzkopf and designed by Werner Stengel, the roller coaster opened to the public on May 8, 1976.  The New Revolution is the world's first modern roller coaster to feature a vertical loop and has been recognized for that accomplishment by American Coaster Enthusiasts (ACE), who awarded the roller coaster its Coaster Landmark status.","wikiUrl":"https://en.wikipedia.org/wiki/The_New_Revolution","formerNames":["Revolution  La Revolución  Great American Revolution"]},
  'volcano-the-blast-coaster': {"description":"Volcano: The Blast Coaster, or simply Volcano, was an inverted launched roller coaster located at Kings Dominion in Doswell, Virginia, United States.  Designed by Werner Stengel, it was the first launched roller coaster manufactured by Intamin and the first of its kind in the world to be inverted.  Its launch mechanism utilized linear induction motor (LIM) technology.","wikiUrl":"https://en.wikipedia.org/wiki/Volcano%3A_The_Blast_Coaster"},
  'loch-ness-monster': {"description":"Loch Ness Monster is a steel roller coaster located at Busch Gardens Williamsburg in Williamsburg, Virginia.  Manufactured by Arrow Development and designed by Ron Toomer, it was the first roller coaster in the world to feature interlocking loops.  The roller coaster was opened within the park's Scottish hamlet, Heatherdowns, on June 2, 1978, and relates to the legend of the Loch Ness Monster.","wikiUrl":"https://en.wikipedia.org/wiki/Loch_Ness_Monster_(roller_coaster)"},
  'shockwave': {"description":"Shockwave was a steel roller coaster at Six Flags Great America in Gurnee, Illinois, United States, located in the Orleans Place section of the park.  Manufactured by Arrow Dynamics, the coaster opened in 1988 as the world's tallest roller coaster and the fastest steel coaster, standing 170 ft tall and reaching speeds of 65 mph.  It featured seven inversions, a record at the time, including three vertical loops, a batwing, and a double corkscrew.","wikiUrl":"https://en.wikipedia.org/wiki/Shockwave_(Six_Flags_Great_America)"},
  'american-eagle': {"description":"American Eagle is a wooden racing roller coaster located at Six Flags Great America theme park in Gurnee, Illinois.  It was the first wooden roller coaster designed by Intamin of Switzerland and was built in 1981 by the contracting firm Figley-Wright at a cost of $10 million.  While most of the records have since been broken, American Eagle had the longest drop and fastest speeds among wooden roller coasters when it debuted and is still recognized as a top racing coaster in the United States.","wikiUrl":"https://en.wikipedia.org/wiki/American_Eagle_(roller_coaster)"},
  'iron-rattler': {"description":"Iron Rattler is a steel roller coaster located at Six Flags Fiesta Texas in San Antonio.  The ride originally opened in 1992 as Rattler, the tallest wooden roller coaster in the world.  It was converted to steel in 2013 by Rocky Mountain Construction (RMC), led by designer Alan Schilke, and reopened as Iron Rattler.","wikiUrl":"https://en.wikipedia.org/wiki/Iron_Rattler"},
  'silver-star': {"description":"Silver Star is a steel roller coaster located at Europa-Park, a theme park in Rust, Baden-Württemberg, Germany.  The coaster has a height of 73 m and a drop of 67 metres (220 ft), placing it in the hyper coaster category.  At the time of its opening, Silver Star was the tallest coaster constructed by Bolliger & Mabillard (B&M), as well as the tallest and fastest coaster in Europe.","wikiUrl":"https://en.wikipedia.org/wiki/Silver_Star_(roller_coaster)"},
  'storm-runner': {"description":"Storm Runner is a launched roller coaster located at Hersheypark in Hershey, Pennsylvania.  Manufactured by Intamin Amusement Rides and located in the Pioneer Frontier section of the park, the Accelerator Coaster opened to the public on May 8, 2004.  It reaches a maximum height of 150 ft, a largest drop of 180 feet, and launches from 0 to 72 mph in two seconds.","wikiUrl":"https://en.wikipedia.org/wiki/Storm_Runner"},
  'do-dodonpa': {"description":"Do-Dodonpa (ド･ドドンパ), formerly known as Dodonpa (ドドンパ), was a steel roller coaster located at Fuji-Q Highland in Fujiyoshida, Yamanashi, Japan.  Manufactured by S&S – Sansei Technologies, the launched coaster used compressed air to propel its trains.  It opened on 21 December 2001 as the fastest roller coaster in the world with the fastest acceleration, reaching a top speed of 172 km/h in 1.","wikiUrl":"https://en.wikipedia.org/wiki/Do-Dodonpa"},
  'jersey-devil-coaster': {"description":"The Jersey Devil Coaster is a single-rail roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  The roller coaster was built by Rocky Mountain Construction (RMC).  It is themed to the Jersey Devil, a mythical creature rumored to live in the New Jersey Pine Barrens.","wikiUrl":"https://en.wikipedia.org/wiki/Jersey_Devil_Coaster"},
  'alpenfury': {"description":"AlpenFury is a steel launched roller coaster located at Canada's Wonderland in Vaughan, Ontario, Canada.  Manufactured by Premier Rides, the ride opened to the public on 12 July 2025 and was marketed as the tallest, fastest, and longest launch coaster in Canada.  It features nine inversions and became the park's 18th roller coaster.","wikiUrl":"https://en.wikipedia.org/wiki/AlpenFury"},
  'apollos-chariot': {"description":"Apollo's Chariot is a steel roller coaster at the Busch Gardens Williamsburg amusement park in James City County, Virginia, United States.  The ride was the first Hyper Coaster designed by Swiss firm Bolliger & Mabillard.  It officially opened to the public on March 27, 1999.","wikiUrl":"https://en.wikipedia.org/wiki/Apollo's_Chariot"},
  'blue-fire-megacoaster': {"description":"Blue Fire megacoaster is a launched roller coaster at Europa-Park.  The coaster opened in 2009 as part of a new Iceland-themed expansion to Europa-Park.  As the first launched coaster built by Mack Rides, Blue Fire was the park's tenth roller coaster and the first to feature inversions.","wikiUrl":"https://en.wikipedia.org/wiki/Blue_Fire"},
  'dominator': {"description":"Dominator is a floorless roller coaster located at Kings Dominion amusement park in Doswell, Virginia.  Built by Bolliger & Mabillard, it originally opened in 2000 as Batman: Knight Flight at Six Flags Ohio (later renamed to Six Flags Worlds of Adventure in 2001), in Aurora, Ohio.  It was given its current name when Cedar Fair purchased the Ohio park in 2004.","wikiUrl":"https://en.wikipedia.org/wiki/Dominator_(roller_coaster)","formerNames":["Batman: Knight Flight at Six Flags Ohio/Six Flags Worlds of Adventure"]},
  'outlaw-run': {"description":"Outlaw Run is a wooden roller coaster located at Silver Dollar City in Branson, Missouri.  Designed by Alan Schilke, Outlaw Run is the first wooden roller coaster manufactured by Rocky Mountain Construction (RMC) and became the first wooden coaster with multiple inversions.  It features a 162 ft drop, three inversions, and a maximum speed of 68 mph, making Outlaw Run the sixth-fastest wooden coaster in the world.","wikiUrl":"https://en.wikipedia.org/wiki/Outlaw_Run"},
  'griffon': {"description":"Griffon is a steel roller coaster located at Busch Gardens Williamsburg amusement park in James City County, Virginia, United States.  Designed by Bolliger & Mabillard (B&M), the Dive Coaster model opened to the public on May 18, 2007.  It climbs to a height of 205 ft and reaches a maximum speed of 71 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Griffon_(roller_coaster)"},
  'lightning-rod': {"description":"Lightning Rod is a hybrid roller coaster located at Dollywood theme park in Pigeon Forge, Tennessee.  Manufactured by Rocky Mountain Construction (RMC), the ride is themed to hot rod cars from the 1950s and opened to the public on June 13, 2016.  Initially marketed as the first launched wooden roller coaster of its kind, Lightning Rod was later modified for the 2021 season, with over half of its wooden Topper Track being replaced with RMC's steel I-Box track.","wikiUrl":"https://en.wikipedia.org/wiki/Lightning_Rod_(roller_coaster)"},
  'drachen-fire': {"description":"Drachen Fire was a steel roller coaster located at Busch Gardens Williamsburg in Williamsburg, Virginia.  Manufactured by Arrow Dynamics, the ride opened to the public in 1992.  Drachen Fire featured a 150 ft lift hill, six inversions, and a zero-gravity camelback element.","wikiUrl":"https://en.wikipedia.org/wiki/Drachen_Fire"},
  'maxx-force': {"description":"Maxx Force is a launched steel roller coaster at Six Flags Great America in Gurnee, Illinois, United States.  Manufactured by S&S – Sansei Technologies, it opened on July 4, 2019.  It is themed on drag racing and is located in the park's Carousel Plaza section.","wikiUrl":"https://en.wikipedia.org/wiki/Maxx_Force"},
  'space-mountain': {"description":"Space Mountain is an indoor, space-themed roller coaster in Tomorrowland at Disneyland in Anaheim, California.  Opened on May 27, 1977, it was the second roller coaster built at Disneyland, and was the second of the five versions of Space Mountain built by The Walt Disney Company.  Its exterior façade is one of Disneyland's three \"mountain\" structures that serve as park landmarks.","wikiUrl":"https://en.wikipedia.org/wiki/Space_Mountain_(Disneyland)"},
  'wonder-woman-flight-of-courage': {"description":"Wonder Woman Flight of Courage is a Rocky Mountain Construction roller coaster at Six Flags Magic Mountain in Valencia, California.  The roller coaster opened on July 16, 2022, as the world's longest and tallest single-rail roller coaster.  It features an 87-degree first drop and three inversions and is located in the DC Universe area of the park, which was expanded and remodeled to include a new restaurant and bar, as well as retail locations featuring exclusive DC Comics merchandise.","wikiUrl":"https://en.wikipedia.org/wiki/Wonder_Woman_Flight_of_Courage"},
  'big-bad-wolf': {"description":"Big Bad Wolf was a suspended roller coaster in the Oktoberfest section of Busch Gardens Williamsburg.  Designed by Arrow Dynamics, the roller coaster opened to the public on June 15, 1984.  The Big Bad Wolf celebrated its 25th Anniversary on June 15th, 2009.","wikiUrl":"https://en.wikipedia.org/wiki/Big_Bad_Wolf_(roller_coaster)"},
  'ghostrider': {"description":"GhostRider is a wooden roller coaster at Knott's Berry Farm in Buena Park, California.  It is located in the Ghost Town section of the park, south of the main entrance.  Manufactured by Custom Coasters International, GhostRider is the longest wooden coaster on the West Coast of the United States, measuring 4533 ft long and 118 ft tall.","wikiUrl":"https://en.wikipedia.org/wiki/GhostRider_(roller_coaster)"},
  'nighthawk': {"description":"Nighthawk was a flying roller coaster located at Carowinds.  Constructed by Vekoma, it was located in the Thunder Road section of the park.  The roller coaster originally opened as Stealth at California's Great America on April 1, 2000.","wikiUrl":"https://en.wikipedia.org/wiki/Nighthawk_(roller_coaster)","formerNames":["Stealth  at California's Great America Borg Assimilator"]},
  'shambhala': {"description":"Shambhala: Expedición al Himalaya is a steel hypercoaster located at PortAventura Park in Salou and Vila-seca, Spain.  Manufactured by Bolliger & Mabillard, it was the tallest (76 m) and second fastest (134 km/h) roller coaster in Europe at the time of its opening.  The height and speed records were beaten in April 2017 by Red Force (with a height of 112 m), which was also opened in PortAventura World in its new theme park Ferrari Land.","wikiUrl":"https://en.wikipedia.org/wiki/Shambhala_(roller_coaster)"},
  'star-wars-hyperspace-mountain': {"description":"Star Wars: Hyperspace Mountain (formerly known as Space Mountain: Mission 2 and Space Mountain: De la Terre á la Lune) is an indoor/outdoor steel roller coaster in Discoveryland at Disneyland Paris.  Originally themed around Jules Verne's classic 1865 novel From the Earth to the Moon, the attraction first opened on June 1, 1995, three years after the park's debut in an attempt to draw more guests to the financially unstable European resort.  Unlike other Space Mountain attractions at Disney theme parks, the installation at Disneyland Paris had a steampunk-detailed appearance with a Columbiad Cannon and a plate-and-rivet exterior under its previous theme.","wikiUrl":"https://en.wikipedia.org/wiki/Star_Wars_Hyperspace_Mountain","formerNames":["Space Mountain: De la Terre à la Lune  Space Mountain: Mission 2"]},
  'twisted-timbers': {"description":"Twisted Timbers is a hybrid roller coaster built by American manufacturer Rocky Mountain Construction and located at Kings Dominion in Doswell, Virginia.  It originally opened as a wooden coaster named Hurler in 1994, designed and manufactured by International Coasters, Inc, as an exact clone of Hurler at Carowinds.  The ride closed for \"extensive maintenance\" in 2015 according to the park, which later teased in 2016 that Hurler was being replaced.","wikiUrl":"https://en.wikipedia.org/wiki/Twisted_Timbers"},
  'voltron-nevera': {"description":"Voltron Nevera (or simply Voltron) is a multi-launch roller coaster at Europa-Park in Rust, Germany.  The ride opened to the public on 26 April 2024 as part of a new Croatian-themed area in the park.  Voltron Nevera was manufactured by Mack Rides at their factory in Waldkirch, Baden-Württemberg.","wikiUrl":"https://en.wikipedia.org/wiki/Voltron_Nevera"},
  'eejanaika': {"description":"Eejanaika (ええじゃないか) is a steel fourth-dimension hypercoaster at Fuji-Q Highland in Fujiyoshida, Yamanashi, Japan.  The ride opened on 19 July 2006 as the world's second fourth dimension coaster.  Eejanaika is taller, faster, and longer than its predecessor, X2, at Six Flags Magic Mountain.","wikiUrl":"https://en.wikipedia.org/wiki/Eejanaika_(roller_coaster)"},
  'the-bat': {"description":"The Bat is a suspended roller coaster located at Kings Island in Mason, Ohio, United States.  Built by Arrow Dynamics, the roller coaster originally opened as Top Gun in 1993, themed to the 1986 film Top Gun.  It is the second suspended coaster to open at the park following an earlier prototype from Arrow Development — also called The Bat – that briefly operated at Kings Island from 1981 to 1983.","wikiUrl":"https://en.wikipedia.org/wiki/The_Bat_(Kings_Island%3B_opened_1993)","formerNames":["Top Gun  and Flight Deck"]},
  'the-dark-knight-coaster': {"description":"The Dark Knight Coaster is a Batman-themed indoor steel roller coaster attraction located at Six Flags Great Adventure, Six Flags Great America, and Six Flags México.  They opened in 2008 and 2009, timed closely to the theatrical release of The Dark Knight.  All three installations were manufactured by Mack Rides.","wikiUrl":"https://en.wikipedia.org/wiki/The_Dark_Knight_Coaster"},
  'rita': {"description":"Rita, formerly known as Rita: Queen of Speed, is a launched roller coaster located in the Dark Forest section of Alton Towers amusement park in Staffordshire Moorlands, England.  Designed by Intamin, the Accelerator Coaster model opened to the public on 1 April 2005.  It features an acceleration from 0 to 98.","wikiUrl":"https://en.wikipedia.org/wiki/Rita_(roller_coaster)","formerNames":["Rita: Queen of Speed"]},
  'pantheon': {"description":"Pantheon is a steel roller coaster at Busch Gardens Williamsburg theme park in Williamsburg, Virginia.  Manufactured by Intamin, the roller coaster opened to park members on March 4, 2022 and features four launches, five airtime hills, and a 95-degree beyond vertical drop.  The 178 ft inverts riders twice and reaches a maximum speed of 73 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Pantheon_(roller_coaster)"},
  'rock-n-roller-coaster-starring-aerosmith': {"description":"Rock 'n' Roller Coaster Starring Aerosmith is an indoor launched roller coaster located at Disney's Hollywood Studios within Walt Disney World.  Manufactured by Vekoma, the roller coaster opened to the public on July 29, 1999.  It uses linear motor electromagnetic technology for acceleration, which propels riders from 0 to 57 mph in 2.","wikiUrl":"https://en.wikipedia.org/wiki/Rock_'n'_Roller_Coaster_Starring_Aerosmith"},
  'verbolten': {"description":"Verbolten is a Zierer multi-launched partially enclosed steel roller coaster at Busch Gardens Williamsburg in Williamsburg, Virginia.  The concept was jointly designed by the park's creative design team and by Zierer of Germany.  \"Verbolten\" is a play on words of the German word verboten, which translates to \"forbidden\" in English.","wikiUrl":"https://en.wikipedia.org/wiki/Verbolten"},
  'alpengeist': {"description":"Alpengeist is an inverted roller coaster at Busch Gardens Williamsburg in Williamsburg, Virginia.  Manufactured by Bolliger & Mabillard, Alpengeist has an Alpine mountain region theme and opened in 1997 as the tallest inverted coaster in the world.  The name \"Alpengeist\" is German for \"Alpine Ghost\" and the ride is themed to a runaway ski lift.","wikiUrl":"https://en.wikipedia.org/wiki/Alpengeist"},
  'stealth': {"description":"Stealth is a hydraulically launched steel roller coaster located in the Amity area of Thorpe Park in Surrey, England.  Designed and manufactured by Intamin of Switzerland at a cost of £12 million, the Accelerator Coaster opened in 2006.  Upon its opening, it was the fastest roller coaster in the United Kingdom, a record later surpassed by Hyperia in 2024.","wikiUrl":"https://en.wikipedia.org/wiki/Stealth_(roller_coaster)"},
  'viper-six-flags-great-adventure': {"description":"Viper was a steel roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  Manufactured by TOGO at an estimated cost of $4 million, the ride opened to the public in June 1995.  It replaced another steel coaster manufactured by TOGO, Ultra Twister, which was removed in 1989.","wikiUrl":"https://en.wikipedia.org/wiki/Viper_(Six_Flags_Great_Adventure)"},
  'arkansas-twister': {"description":"Arkansas Twister is a retired wooden roller coaster at Magic Springs and Crystal Falls amusement park in Hot Springs, Arkansas.  Originally opening in 1978 as The Roaring Tiger at Circus World theme park, the roller coaster was purchased in 1991 by Magic Springs, where it reopened as Arkansas Twister on May 30, 1992.  It features a 92 ft and reaches speeds of up to 50 mph as it travels through the foothills of the Ouachita Mountains.","wikiUrl":"https://en.wikipedia.org/wiki/Arkansas_Twister","formerNames":["Florida Hurricane  Michael Jackson's Thrill Coaster  The Roaring Tiger"]},
  'sooperdooperlooper': {"description":"SooperDooperLooper (stylized as sooperdooperLooper) is a steel roller coaster at Hersheypark in Hershey, Pennsylvania, United States.  Designed and manufactured by Anton Schwarzkopf, the roller coaster opened to the public on May 8, 1977.  SooperDooperLooper is located in The Hollow section of the park and cost more than $3 million to construct and build.","wikiUrl":"https://en.wikipedia.org/wiki/SooperDooperLooper"},
  'ninja': {"description":"Ninja is a suspended roller coaster located at Six Flags Magic Mountain in Valencia, California.  It is the fastest roller coaster of its kind in the world, joint with Vortex at Canada's Wonderland, both with top speeds of 55 mph (89 km/h).","wikiUrl":"https://en.wikipedia.org/wiki/Ninja_(Six_Flags_Magic_Mountain)"},
  'west-coast-racers': {"description":"West Coast Racers is a dueling steel roller coaster located at Six Flags Magic Mountain theme park in Valencia, California.  Manufactured by Premier Rides, the ride is a collaboration between West Coast Customs and Six Flags that was promoted as the world's first launch version of a racing roller coaster.  After multiple delays and missing the 2019 summer season, the ride eventually debuted on December 21, 2019, in a series of preview events spanning several weeks.","wikiUrl":"https://en.wikipedia.org/wiki/West_Coast_Racers"},
  'corkscrew-alton-towers': {"description":"Corkscrew was a steel roller coaster located at Alton Towers theme park, in the United Kingdom.  Corkscrew was manufactured for Alton Towers by Dutch company Vekoma, engineered by Werner Stengel of German Ing. -Büro Stengel GmbH (Ingenieur Büro Stengel).","wikiUrl":"https://en.wikipedia.org/wiki/Corkscrew_(Alton_Towers)"},
  'flashback': {"description":"Flashback was a steel roller coaster made by Intamin of Switzerland.  The coaster was located in the Six Flags Plaza area of Six Flags Magic Mountain in Valencia, California.  The model of the ride, a Space Diver coaster, was intended to be mass-produced, however, Flashback was the only installation.","wikiUrl":"https://en.wikipedia.org/wiki/Flashback_(Six_Flags_Magic_Mountain)","formerNames":["Z-Force  at Six Flags Over Georgia and Six Flags Great America"]},
  'fujiyama': {"description":"Fujiyama (フジヤマ) is a steel roller coaster at Fuji-Q Highland, Fujiyoshida, Japan.  When Fujiyama opened in July 1996, it was the world's tallest roller coaster at 259 ft, and had the largest drop in the world at 230 ft.  Fujiyama was also the world's fastest roller coaster for a year of its operation, being succeeded by Tower of Terror at Dreamworld theme park in Queensland, Australia in 1997.","wikiUrl":"https://en.wikipedia.org/wiki/Fujiyama_(roller_coaster)"},
  'montu': {"description":"Montu is an inverted roller coaster at Busch Gardens Tampa Bay in Tampa, Florida.  Designed by Swiss manufacturer Bolliger & Mabillard, it is the park's second roller coaster designed by that company following the success of Kumba, which opened 3 years prior.  When the ride opened on May 16, 1996, it was the world's tallest and fastest inverted roller coaster, a title it has since conceded to Alpengeist at sister park Busch Gardens Williamsburg.","wikiUrl":"https://en.wikipedia.org/wiki/Montu_(roller_coaster)"},
  'the-voyage': {"description":"The Voyage is a wooden roller coaster located at Holiday World & Splashin' Safari in Santa Claus, Indiana.  Designed and built by The Gravity Group with the help of designers Mike Graham, Korey Kiepert, Larry Bill, Chad Miller, and former park president Will Koch, the hybrid coaster is themed to the famous voyage of the Mayflower by Pilgrims to North America in 1620.  It opened to the public on May 6, 2006.","wikiUrl":"https://en.wikipedia.org/wiki/The_Voyage_(roller_coaster)"},
  'cheetah-hunt': {"description":"Cheetah Hunt is a steel launched roller coaster at Busch Gardens Tampa Bay in Tampa, Florida.  The roller coaster was manufactured by Intamin and designed in collaboration with Mark Rose.  Cheetah Hunt opened to the public on May 27, 2011, alongside a cheetah exhibit called Cheetah Run.","wikiUrl":"https://en.wikipedia.org/wiki/Cheetah_Hunt"},
  'great-bear': {"description":"Great Bear is an inverted roller coaster located at Hersheypark in Hershey, Pennsylvania, United States.  Designed and manufactured by Bolliger & Mabillard, with additional design from Werner Stengel, the roller coaster opened on May 23, 1998, in the Minetown section of the park.  Great Bear was the first inverted looping coaster in Pennsylvania and cost $13 million, the largest project Hersheypark undertook at the time.","wikiUrl":"https://en.wikipedia.org/wiki/Great_Bear_(roller_coaster)"},
  'kumba': {"description":"Kumba is a steel roller coaster located at Busch Gardens Tampa Bay in Tampa, Florida.  Manufactured by Bolliger & Mabillard, the ride opened in 1993.  It stands 143 ft tall and has a top speed of 60 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Kumba_(roller_coaster)"},
  'mako': {"description":"Mako is a steel roller coaster located at SeaWorld Orlando in Orlando, Florida, United States.  Manufactured by Bolliger & Mabillard, the hypercoaster model opened to the public on June 10, 2016.  Mako is named after the mako shark and is located in the Sea of Mystery section of the park.","wikiUrl":"https://en.wikipedia.org/wiki/Mako_(roller_coaster)"},
  'montezooma-the-forbidden-fortress': {"description":"MonteZOOMa: The Forbidden Fortress, previously known as Montezooma’s Revenge, is a shuttle roller coaster located at Knott's Berry Farm in Buena Park, California, United States.  Designed by Werner Stengel and built by Schwarzkopf Industries GmbH, the ride opened to the public on May 21, 1978.  It is one of eight flywheel-launched units around the world and the oldest looping shuttle coaster still operating in its original location.","wikiUrl":"https://en.wikipedia.org/wiki/MonteZOOMa%3A_The_Forbidden_Fortress","formerNames":["Montezooma's Revenge"]},
  'demon': {"description":"Demon is a looping roller coaster located at Six Flags Great America in Gurnee, Illinois and California's Great America in Santa Clara, California.  The pair of steel roller coasters opened in 1976 as Turn of the Century when both parks were owned by the Marriott Corporation.  They were custom-designed and manufactured by Arrow Dynamics, each featuring a 102 ft, 2130 ft course including two airtime hills and one of the first double corkscrew elements on a roller coaster.","wikiUrl":"https://en.wikipedia.org/wiki/Demon_(roller_coaster)","formerNames":["Turn of the Century"]},
  'jolly-rancher-remix': {"description":"Jolly Rancher Remix (formerly Sidewinder) is a steel shuttle roller coaster located at Hersheypark in Hershey, Pennsylvania, United States.  A Boomerang model manufactured by Vekoma and designed by Peter Clerx, the roller coaster originally opened as the Sidewinder on May 11, 1991.  The roller coaster debuted in the Pioneer Frontier section of the park and cost $4.","wikiUrl":"https://en.wikipedia.org/wiki/Jolly_Rancher_Remix","formerNames":["Sidewinder"]},
  't-express': {"description":"T Express is a wooden roller coaster at the Everland theme park in Yongin, South Korea.  T Express opened on March 14, 2008, in the European Adventure section of the park, and is themed after a small town in the Alps.  The coaster was constructed by Intamin, a Swiss manufacturing company, and designed by Ing.","wikiUrl":"https://en.wikipedia.org/wiki/T_Express"},
  'king-cobra': {"description":"King Cobra was a stand-up roller coaster located at Kings Island in Mason, Ohio.  Manufactured by TOGO, the roller coaster operated from 1984 to 2001, and it was the first in the world to be designed from the ground up as a stand-up configuration.  Other stand-up coasters that preceded King Cobra were sit-down models later modified to accommodate stand-up trains.","wikiUrl":"https://en.wikipedia.org/wiki/King_Cobra_(roller_coaster)"},
  'mindbender': {"description":"The Mindbender was an Anton Schwarzkopf looping roller coaster at Galaxyland, a theme park in West Edmonton Mall, in Alberta, Canada.  The ride officially opened to the public on December 20, 1985 at a cost of $6 million.  At 44.","wikiUrl":"https://en.wikipedia.org/wiki/Mindbender_(Galaxyland)"},
  'saw-the-ride': {"description":"Saw – The Ride is a steel roller coaster located at Thorpe Park in Surrey, England.  Manufactured by Gerstlauer, the ride is a Euro-Fighter model that opened to the public on 14 March 2009.  At the time of its debut, it was promoted as the steepest freefall roller coaster in the world, featuring a 100-degree drop.","wikiUrl":"https://en.wikipedia.org/wiki/Saw_%E2%80%93_The_Ride"},
  'the-big-one': {"description":"The Big One (formerly Pepsi Max Big One) is a steel hypercoaster at Pleasure Beach Resort (better known as Blackpool Pleasure Beach) in Blackpool, England.  Designed by Ron Toomer and manufactured by Arrow Dynamics, the ride opened to the public on 28 May 1994 as the tallest roller coaster in the world, featuring a height of 65 metres (213 ft).  It held the title as the tallest until Fujiyama opened in 1996.","wikiUrl":"https://en.wikipedia.org/wiki/The_Big_One_(roller_coaster)","formerNames":["Pepsi Max Big One"]},
  'thunder-road': {"description":"Thunder Road was a wooden roller coaster located at Carowinds amusement park on the border between Fort Mill, South Carolina, and Charlotte, North Carolina.  Opened in 1976 and built by Philadelphia Toboggan Coasters, the racing roller coaster cost $1. 6 million to construct and featured two identical tracks that paralleled each other.","wikiUrl":"https://en.wikipedia.org/wiki/Thunder_Road_(roller_coaster)"},
  'zadra': {"description":"Zadra (English: Splinter) is a steel roller coaster located at Energylandia in Zator, Poland.  It was built and designed by American manufacturer Rocky Mountain Construction (RMC).  The ride opened in 2019.","wikiUrl":"https://en.wikipedia.org/wiki/Zadra_(roller_coaster)"},
  'goliath-six-flags-over-georgia': {"description":"Goliath is a steel roller coaster located at the Six Flags Over Georgia amusement park in Cobb County, Georgia.  The Hyper Coaster model manufactured by Bolliger & Mabillard climbs to a height of 200 ft and reaches a maximum speed of 70 mph.  Before its construction, the Great Gasp and Looping Starship attractions were removed to make room for Goliath, which opened to the public on April 1, 2006.","wikiUrl":"https://en.wikipedia.org/wiki/Goliath_(Six_Flags_Over_Georgia)"},
  'hurler': {"description":"Hurler is a wooden roller coaster located at Carowinds amusement park in Charlotte, North Carolina.  A second identical installation of the ride was also built at Kings Dominion, and both locations opened to the public in 1994.  The Hurler at Kings Dominion was closed following the 2015 season and was renovated by Rocky Mountain Construction, re-emerging as a hybrid coaster in 2018 named Twisted Timbers.","wikiUrl":"https://en.wikipedia.org/wiki/Hurler_(roller_coaster)"},
  'rolling-thunder': {"description":"Rolling Thunder was a racing roller coaster located at Six Flags Great Adventure in Jackson Township, New Jersey.  Designed by William Cobb, it opened in 1979 as the park's first wooden coaster during its fifth operating season.  Rolling Thunder closed permanently in 2013 to make room for Zumanjaro: Drop of Doom, which opened in 2014 and was removed in 2024.","wikiUrl":"https://en.wikipedia.org/wiki/Rolling_Thunder_(roller_coaster)"},
  'steel-force': {"description":"Steel Force is a steel roller coaster located at Dorney Park & Wildwater Kingdom in Allentown, Pennsylvania.  At 5600 ft in length, Steel Force is tied with Mamba at Worlds of Fun as the ninth-longest steel coaster in the world as of 2026. \n\nBuilt by D.","wikiUrl":"https://en.wikipedia.org/wiki/Steel_Force"},
  'firebird': {"description":"Firebird is a defunct floorless roller coaster located at Six Flags America in Prince George's County, Maryland, United States.  Originally designed as a stand-up roller coaster by Swiss manufacturer Bolliger & Mabillard (B&M), the ride first opened as Iron Wolf in 1990 at Six Flags Great America.  It debuted as the tallest and fastest stand-up coaster in the world, featuring a height of 100 ft and a maximum speed of 55 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Firebird_(roller_coaster)","formerNames":["Iron Wolf","Apocalypse"]},
  'psyclone': {"description":"Psyclone was a wooden roller coaster located at Six Flags Magic Mountain in Santa Clarita, California.  Designed by Curtis D.  Summers and constructed by the Dinn Corporation, the roller coaster opened to the public on March 23, 1991.","wikiUrl":"https://en.wikipedia.org/wiki/Psyclone_(roller_coaster)"},
  'backlot-stunt-coaster': {"description":"Backlot Stunt Coaster is a family launched roller coaster located at three Six Flags amusement parks.  The first two installations opened at Kings Island and Canada's Wonderland in 2005 under the name Italian Job: Stunt Track, while the third opened at Kings Dominion in 2006 as Italian Job: Turbo Coaster.  All three were themed to the climactic chase scene at the end of the 2003 film The Italian Job and were installed when the parks were owned by Paramount Parks.","wikiUrl":"https://en.wikipedia.org/wiki/Backlot_Stunt_Coaster","formerNames":["Italian Job: Stunt Track  Italian Job: Turbo Coaster"]},
  'iron-dragon': {"description":"Iron Dragon is a suspended roller coaster located at Cedar Point in Sandusky, Ohio.  Built in 1987 by Arrow Dynamics, it is located in the Millennium Midway section of the park.","wikiUrl":"https://en.wikipedia.org/wiki/Iron_Dragon_(roller_coaster)"},
  'wildcat-cedar-point': {"description":"WildCat was a steel roller coaster located at Cedar Point in Sandusky, Ohio.  Designed by Werner Stengel and manufactured by Anton Schwarzkopf, the ride opened to the public in 1979.  Cedar Point decided in 2012 to remove WildCat to allow for expansion of the Celebration Plaza, also citing that the coaster had reached the end of its service life.","wikiUrl":"https://en.wikipedia.org/wiki/WildCat_(Cedar_Point)"},
  'fahrenheit': {"description":"Fahrenheit is a steel roller coaster at Hersheypark in Hershey, Pennsylvania, United States.  Located in the Pioneer Frontier section of the park, the roller coaster was manufactured by Intamin and opened on May 24, 2008.  It features six inversions and became the steepest roller coaster in the world when it opened with its first drop of 97 degrees.","wikiUrl":"https://en.wikipedia.org/wiki/Fahrenheit_(roller_coaster)"},
  'shock-wave': {"description":"Shock Wave is a steel roller coaster located at Six Flags Over Texas in Arlington, Texas.  Built right at the edge of the park, Shock Wave is easily seen by passers-by on Interstate Highway 30.  Its unique four-sided tube truss track system is similar to The Riddler Mindbender roller coaster at Six Flags Over Georgia which was constructed at the same time.","wikiUrl":"https://en.wikipedia.org/wiki/Shock_Wave_(Six_Flags_Over_Texas)"},
  'tmnt-shellraiser': {"description":"TMNT Shellraiser is a steel indoor roller coaster at Nickelodeon Universe amusement park, within the American Dream mall, in East Rutherford, New Jersey, United States.  The roller coaster is a Euro-Fighter model manufactured by Gerstlauer, and is themed to the 2012 Teenage Mutant Ninja Turtles series.  It is the steepest roller coaster in the world, with a vertical drop of 121.","wikiUrl":"https://en.wikipedia.org/wiki/TMNT_Shellraiser"},
  'tron-lightcycle-power-run': {"description":"Tron Lightcycle Power Run (stylized as TRON Lightcycle Power Run; 创极速光轮) and Tron Lightcycle / Run (stylized as TRON Lightcycle / Run) are semi-enclosed, launched roller coasters at Shanghai Disneyland and at Magic Kingdom in Walt Disney World.  Based on the Tron franchise, the first incarnation opened at Shanghai Disneyland on June 16, 2016.  A nearly identical installation opened at Magic Kingdom in Walt Disney World on April 4, 2023.","wikiUrl":"https://en.wikipedia.org/wiki/Tron_Lightcycle_Power_Run"},
  'afterburn': {"description":"Afterburn is an inverted roller coaster located at Carowinds amusement park in Charlotte, North Carolina.  After more than two years of planning and construction, the roller coaster opened on March 20, 1999.  The ride previously operated as Top Gun: The Jet Coaster, before it was renamed following Cedar Fair's purchase of Paramount Parks in 2006.","wikiUrl":"https://en.wikipedia.org/wiki/Afterburn_(roller_coaster)","formerNames":["Top Gun: The Jet Coaster"]},
  'dc-rivals-hypercoaster': {"description":"DC Rivals HyperCoaster is a steel hypercoaster at Warner Bros.  Movie World on the Gold Coast, Queensland, Australia.  Manufactured by Mack Rides, it is the fastest, longest and tallest hypercoaster in the Southern Hemisphere.","wikiUrl":"https://en.wikipedia.org/wiki/DC_Rivals_HyperCoaster"},
  'hypersonic-xlc': {"description":"Hypersonic XLC was a roller coaster located at Kings Dominion in Doswell, Virginia.  Hypersonic was built by S&S Worldwide (now S&S – Sansei Technologies), a company specializing in air-powered rides, and was the first compressed air launch coaster in the world.  Hypersonic was S&S Worldwide's actual prototype for an air-launched coaster, called Thrust Air 2000.","wikiUrl":"https://en.wikipedia.org/wiki/Hypersonic_XLC"},
  'apocalypse-the-ride': {"description":"Apocalypse: The Ride, formerly known as Terminator Salvation: The Ride, is a wooden roller coaster located at Six Flags Magic Mountain in Valencia, California.  Manufactured by Great Coasters International, the roller coaster opened to the public on May 23, 2009.  It is located in The Underground section of the amusement park on a plot of land formerly occupied by the Psyclone (1991–2007), Shockwave (1986–1988) and Sarajevo Bobsleds (1984–1986).","wikiUrl":"https://en.wikipedia.org/wiki/Apocalypse%3A_The_Ride","formerNames":["Terminator Salvation: The Ride"]},
  'big-apple-coaster': {"description":"The Big Apple Coaster (formerly Manhattan Express and The Roller Coaster) is a steel roller coaster at the New York-New York Hotel and Casino on the Las Vegas Strip in Paradise, Nevada, United States.  The ride's trains are themed to New York City taxicabs.  Opened on January 3, 1997, it is the only roller coaster by Japanese roller coaster manufacturer TOGO still operating in North America.","wikiUrl":"https://en.wikipedia.org/wiki/Big_Apple_Coaster","formerNames":["Manhattan Express  The Roller Coaster"]},
  'time-traveler': {"description":"Time Traveler is a spinning roller coaster located at Silver Dollar City in Branson, Missouri.  The roller coaster was manufactured by Mack Rides in collaboration with the park's in-house team.  The original concept for the roller coaster was conceived from a prototype train tested on another roller coaster, Blue Fire, at Europa-Park in Germany.","wikiUrl":"https://en.wikipedia.org/wiki/Time_Traveler_(roller_coaster)"},
  'steel-taipan': {"description":"Steel Taipan is a steel launched roller coaster at Dreamworld in Coomera, Queensland, Australia.  Steel Taipan is a direct replacement to the former Thunder River Rapids Ride.  The roller coaster, the first triple-launched coaster in the Southern Hemisphere, is named after the deadly Taipan family of snakes native to Australia.","wikiUrl":"https://en.wikipedia.org/wiki/Steel_Taipan"},
  'time-warp': {"description":"Time Warp, formerly known as Tomb Raider: The Ride, was a flying roller coaster located at Canada's Wonderland.  Manufactured by Zamperla, the ride opened to the public on 2 May 2004.  Following Cedar Fair's (merged with Six Flags in July 2024 under the Six Flags name) removal of themes based on Paramount IP from its parks, including Kings Island and Kings Dominion, Time Warp became the last attraction at a Six Flags park to be themed to the Tomb Raider franchise.","wikiUrl":"https://en.wikipedia.org/wiki/Time_Warp_(roller_coaster)","formerNames":["Tomb Raider: The Ride"]},
  'kraken': {"description":"Kraken is a steel roller coaster at SeaWorld Orlando in Orlando, Florida, United States.  Manufactured by Bolliger & Mabillard, the ride opened as the second longest floorless coaster in the world on June 1, 2000, with a track length measuring 4177 ft.  It features a total of seven inversions and reaches a maximum speed of 65 mph.","wikiUrl":"https://en.wikipedia.org/wiki/Kraken_(roller_coaster)","formerNames":["Kraken Unleashed"]},
  'the-flash-vertical-velocity-six-flags-great-adventure': {"description":"The Flash: Vertical Velocity is a steel roller coaster at Six Flags Great Adventure in Jackson Township, New Jersey.  It is a Vekoma Super Boomerang launch coaster themed to the DC Comics character the Flash. \n\nAlso a shuttle roller coaster, The Flash features an Immelmann Stall and a zero-g roll and a top speed of 59 mi/h.","wikiUrl":"https://en.wikipedia.org/wiki/The_Flash%3A_Vertical_Velocity_(Six_Flags_Great_Adventure)"},
  'flight-deck-canadas-wonderland': {"description":"Flight Deck is an inverted roller coaster located at Canada's Wonderland in Vaughan, Ontario, Canada.  It originally opened in 1995 under the name Top Gun.  It was renamed Flight Deck in 2008 after Paramount Parks sold Canada's Wonderland to Cedar Fair, which necessitated the gradual removal of all Paramount names and trademarks from the theme park.","wikiUrl":"https://en.wikipedia.org/wiki/Flight_Deck_(Canada's_Wonderland)","formerNames":["Top Gun"]},
  'the-swarm': {"description":"The Swarm is a steel roller coaster located at Thorpe Park in the United Kingdom.  The Swarm was the world's second Wing Coaster model designed by Swiss roller coaster manufacturer Bolliger & Mabillard and the first one located in the United Kingdom.  Construction commenced in May 2011, and the coaster opened on 15 March 2012.","wikiUrl":"https://en.wikipedia.org/wiki/The_Swarm_(roller_coaster)"},
  'cedar-creek-mine-ride': {"description":"Cedar Creek Mine Ride is a mine train roller coaster at Cedar Point amusement park in Sandusky, Ohio, United States.  Built by Arrow Development, the roller coaster opened in 1969 in the Frontiertown section of the park.  It is the second oldest roller coaster in operation at Cedar Point behind Blue Streak.","wikiUrl":"https://en.wikipedia.org/wiki/Cedar_Creek_Mine_Ride"},
  'desperado': {"description":"Desperado was a steel roller coaster located at Buffalo Bill's Hotel and Casino in Primm, Nevada, United States, a part of the Primm Valley Resorts complex, straddling the state borders of California and Nevada.  Designed by Arrow Dynamics and fabricated by Intermountain Lift, Inc. , Desperado was one of the tallest roller coasters in the world when it opened in 1994, being listed by the Guinness Book of Records as the world's tallest roller coaster (for 1996).","wikiUrl":"https://en.wikipedia.org/wiki/Desperado_(roller_coaster)"},
  'shockwave-kings-dominion': {"description":"Shockwave was a stand-up roller coaster located at Kings Dominion in Doswell, Virginia.  Opened in 1986, it was the third stand-up roller coaster installation built and designed by Japanese company TOGO.  Following closures of the previous two, it became the oldest of its kind still in operation.","wikiUrl":"https://en.wikipedia.org/wiki/Shockwave_(Kings_Dominion)"},
  'guardians-of-the-galaxy-cosmic-rewind': {"description":"Guardians of the Galaxy: Cosmic Rewind is an enclosed roller coaster at Epcot at Walt Disney World, manufactured by Dutch company Vekoma.  Based on the Marvel Cinematic Universe Guardians of the Galaxy films, it is the first attraction at Walt Disney World to feature characters from the Marvel Universe.  Opened on May 27, 2022, it is Epcot's first roller coaster and Disney's first backwards-launched roller coaster.","wikiUrl":"https://en.wikipedia.org/wiki/Guardians_of_the_Galaxy%3A_Cosmic_Rewind"},
  'ultimate': {"description":"The Ultimate was a steel roller coaster located at Lightwater Valley theme park in North Yorkshire, England.  Manufactured by British Rail Engineering Limited, the roller coaster opened in 1991 as the longest roller coaster in the world, surpassing The Beast at Kings Island in the United States.  It held the record until the opening of Steel Dragon 2000 in Japan.","wikiUrl":"https://en.wikipedia.org/wiki/The_Ultimate_(roller_coaster)"},
  'whizzer': {"description":"Whizzer, originally named Willard's Whizzer, is a steel roller coaster located at Six Flags Great America in Gurnee, Illinois, United States.  Designed by Werner Stengel and built by Anton Schwarzkopf, the Speedracer model was one of two identical roller coasters built for the Marriott Corporation in time for the debut of their Great America parks in 1976. \n\nThe first installation of the ride opened with California's Great America on March 20, 1976, and it operated until 1988.","wikiUrl":"https://en.wikipedia.org/wiki/Whizzer_(roller_coaster)","formerNames":["Willard's Whizzer"]},
  'anaconda': {"description":"Anaconda was a steel roller coaster located at Kings Dominion, in the Jungle X-Pedition section of the park.  Built by Arrow Dynamics and designed by Ron Toomer, Anaconda opened in 1991 as the first looping roller coaster to feature an underwater tunnel and the first at Kings Dominion with more than one inversion.","wikiUrl":"https://en.wikipedia.org/wiki/Anaconda_(Kings_Dominion)"},
  'the-flash-vertical-velocity-six-flags-great-america': {"description":"The Flash: Vertical Velocity (originally and colloquially known as Vertical Velocity or V2) is a launched inverted roller coaster located at Six Flags Great America in Gurnee, Illinois, United States.  Manufactured by Intamin, the Impulse roller coaster model opened on May 18, 2001.  It is located in the DC Universe section of the park, receiving its theme to the DC Comics character The Flash in 2022.","wikiUrl":"https://en.wikipedia.org/wiki/The_Flash%3A_Vertical_Velocity_(Six_Flags_Great_America)","formerNames":["Vertical Velocity"]},
  'the-wild-one': {"description":"The Wild One is a decommissioned wooden roller coaster at Six Flags America in Prince George's County, Maryland.  It features a 450° spiral helix and a series of bunny hills that produce a significant amount of air time.  The wooden coaster was previously known as Giant Coaster when it was located at Paragon Park in Hull, Massachusetts.","wikiUrl":"https://en.wikipedia.org/wiki/The_Wild_One_(roller_coaster)","formerNames":["The Giant Coaster"]},
  'toutatis': {"description":"Toutatis is a steel launched roller coaster located at Parc Astérix in Plailly, France.  Toutatis was first announced at the IAAPA Orlando Expo in 2018 and upon opening became France's tallest and fastest coaster.  It features four launches with a top speed of 107 km/h and a 51 m top hat.","wikiUrl":"https://en.wikipedia.org/wiki/Toutatis_(roller_coaster)"},
  'steel-eel': {"description":"Steel Eel is a steel roller coaster located at SeaWorld San Antonio in San Antonio, Texas.  Manufactured and designed by D.  H.","wikiUrl":"https://en.wikipedia.org/wiki/Steel_Eel"},
  'batwing': {"description":"Batwing was a steel flying roller coaster built by Vekoma at Six Flags America in Prince George's County, Maryland.  The ride was a clone of the now-defunct Firehawk at Kings Island, and similar to the also-defunct Nighthawk at Carowinds, however that ride had a slightly different ending, and different paint scheme.  Batwing was the last operating Vekoma Flying Dutchman until its closure in 2025.","wikiUrl":"https://en.wikipedia.org/wiki/Batwing_(roller_coaster)"},
  'f-l-y': {"description":"F. L. Y.","wikiUrl":"https://en.wikipedia.org/wiki/F.L.Y._(roller_coaster)"},
  'flight-deck': {"description":"Flight Deck (formerly Top Gun and briefly as Soaring Chiefs) is an inverted roller coaster located at California's Great America in Santa Clara, California.  Built by Bolliger & Mabillard and designed by Werner Stengel, the roller coaster made its debut on March 20, 1993, as Top Gun.  The roller coaster was built as Paramount, who had purchased the Great America theme park in 1992 along with several other parks, sought to expand its entertainment opportunities and promote its films.","wikiUrl":"https://en.wikipedia.org/wiki/Flight_Deck_(California's_Great_America)","formerNames":["Top Gun  and Soaring Chiefs"]},
  'jack-rabbit': {"description":"Jack Rabbit is a wooden roller coaster located at Kennywood Park in West Mifflin, Pennsylvania.  Designed and built by John A.  Miller and Harry C.","wikiUrl":"https://en.wikipedia.org/wiki/Jack_Rabbit_(Kennywood)"},
  'possessed': {"description":"Possessed is an inverted impulse launched roller coaster located at Dorney Park & Wildwater Kingdom in Allentown, Pennsylvania.  Manufactured by Intamin and designed by Werner Stengel, the roller coaster originally debuted at Six Flags Ohio amusement park as Superman: Ultimate Escape on May 5, 2000.  After Cedar Fair purchased the park and restored its Geauga Lake name in early 2004, the coaster was immediately renamed Steel Venom.","wikiUrl":"https://en.wikipedia.org/wiki/Possessed_(roller_coaster)","formerNames":["Superman: Ultimate Escape at Six Flags Ohio/Six Flags Worlds of Adventure  Steel Venom at Geauga Lake  Voodoo at Dorney Park & Wildwater Kingdom"]},
  'silver-bullet': {"description":"Silver Bullet is a western-theme inverted roller coaster designed by Bolliger & Mabillard located at Knott's Berry Farm, an amusement park in Buena Park, California.  The $16 million roller coaster was announced on December 1, 2003 and opened on December 7, 2004.  The track is approximately 3125 ft long and the lift hill is about 146 ft tall.","wikiUrl":"https://en.wikipedia.org/wiki/Silver_Bullet_(Knott's_Berry_Farm)"},
  'dragon-khan': {"description":"Dragon Khan is a steel sit-down roller coaster in the PortAventura Park theme park in Salou and Vilaseca (Tarragona), Catalonia, Spain.  It has eight inversions, which was a world record until the opening of the ten-inversion Colossus in Thorpe Park, United Kingdom in 2002. \n\nThe ride, built by Bolliger & Mabillard (B&M), opened on May 2, 1995 and was one of the two roller coasters present on PortAventura's opening.","wikiUrl":"https://en.wikipedia.org/wiki/Dragon_Khan"},
  'hollywood-dream-the-ride': {"description":"Hollywood Dream – The Ride (ハリウッド・ドリーム・ザ・ライド) is a steel roller coaster located at Universal Studios Japan.  Designed by Bolliger & Mabillard, it features inbuilt sound systems allowing riders to choose their ride music.","wikiUrl":"https://en.wikipedia.org/wiki/Hollywood_Dream_%E2%80%93_The_Ride"},
  'manta-seaworld-orlando': {"description":"Manta is a steel flying roller coaster at SeaWorld Orlando in Orlando, Florida, United States.  The attraction allows guests to encounter numerous species of ray before boarding a manta ray-shaped train that takes them on a 3359 ft roller coaster ride above the park, reaching top speeds of 56 mph.  Designed by Swiss firm Bolliger & Mabillard, Manta restrains riders in the prone position and features four inversions.","wikiUrl":"https://en.wikipedia.org/wiki/Manta_(SeaWorld_Orlando)"},
  'scooby-doo-spooky-coaster': {"description":"Scooby-Doo Spooky Coaster is an enclosed steel wild mouse roller coaster located at Warner Bros.  Movie World on the Gold Coast, Australia.  It is based on the 2002 live action film Scooby-Doo, which was filmed at the studio adjacent to the park at the same time the ride was being constructed.","wikiUrl":"https://en.wikipedia.org/wiki/Scooby-Doo_Spooky_Coaster"},
  'comet': {"description":"Comet is a wooden roller coaster at Hersheypark in Hershey, Pennsylvania.  It is located in the Hollow section of Hersheypark, next to Skyrush.  Built in 1946 by the Philadelphia Toboggan Coasters (PTC) of Philadelphia, Pennsylvania, the coaster features a double out and back track layout.","wikiUrl":"https://en.wikipedia.org/wiki/Comet_(Hersheypark)"},
  'road-runner-express': {"description":"Road Runner Express is a steel junior roller coaster at Six Flags Magic Mountain in Valencia, California.  On November 4, 2010, Six Flags had an investor meeting webcast where they released the new name for the kid's coaster and location in Bugs Bunny World.  By April 2011, the entire coaster has finished construction on site.","wikiUrl":"https://en.wikipedia.org/wiki/Road_Runner_Express_(Six_Flags_Magic_Mountain)","formerNames":["Rex's Rail Runner"]},
  'taron': {"description":"Taron is a multilaunch steel roller coaster manufactured by Intamin located at Phantasialand in Germany.  It was the fastest multi-launched roller coaster in the world when it opened on 30 June 2016. \n\nThe ride is situated in the 'Klugheim' area of the theme park, a mythical village reflecting Old Norse cultures.","wikiUrl":"https://en.wikipedia.org/wiki/Taron_(roller_coaster)"},
  'tigris': {"description":"Tigris is a steel launched roller coaster at Busch Gardens Tampa Bay theme park in Tampa, Florida, United States.  Built on the former Tanganyika Tidal Wave water ride, Tigris officially opened on April 19, 2019 as the park's ninth roller coaster.  Tigris is located within the Stanleyville section of the park.","wikiUrl":"https://en.wikipedia.org/wiki/Tigris_(roller_coaster)"},
  'eurosat-cancan-coaster': {"description":"Eurosat - CanCan Coaster is an enclosed roller coaster at Europa-Park in Rust, Germany.  The ride is situated inside a 45-metre (148 ft) high geodesic dome, a notable landmark in the park.  Originally opening in 1989, Eurosat was heavily refurbished between 2017 and 2018, which featured the addition of new track and some minor layout changes, as well as the construction of a virtual reality experience with its own separate station.","wikiUrl":"https://en.wikipedia.org/wiki/Eurosat_-_CanCan_Coaster"},
  'th13teen': {"description":"Thirteen (officially stylised as TH13TEEN) is a steel roller coaster at Alton Towers in England.  The ride was constructed by Intamin and opened on 20 March 2010.  It is the world's first vertical freefall drop roller coaster, on which the track and train freefall approximately five metres in darkness.","wikiUrl":"https://en.wikipedia.org/wiki/Thirteen_(roller_coaster)"},
  'adventure-express': {"description":"Adventure Express is a mine train roller coaster located in the Adventure Port section at Kings Island amusement park in Mason, Ohio.  Manufactured by Arrow Dynamics, the roller coaster opened to the public on April 13, 1991.  A portion of the ride's design drew inspiration from the Indiana Jones franchise.","wikiUrl":"https://en.wikipedia.org/wiki/Adventure_Express"},
  'icon': {"description":"Icon (sometimes stylized as ICON) is a launched roller coaster at Pleasure Beach Resort (better known as Blackpool Pleasure Beach) in Blackpool, England.  Manufactured by Mack Rides, the ride opened on 25 May 2018, and had a total cost of £16. 25 million.","wikiUrl":"https://en.wikipedia.org/wiki/Icon_(roller_coaster)"},
  'mamba': {"description":"Mamba is a steel roller coaster located at Worlds of Fun in Kansas City, Missouri.  Designed by Steve Okamoto and manufactured by D. H.","wikiUrl":"https://en.wikipedia.org/wiki/Mamba_(roller_coaster)"},
  'sky-rocket': {"description":"Sky Rocket is a steel roller coaster located at Kennywood amusement park in West Mifflin, Pennsylvania.  Manufactured by Premier Rides, Sky Rocket opened to the public on June 29, 2010.  It was the first major coaster addition at the park in almost a decade, following the renovation of Phantom's Revenge in 2001.","wikiUrl":"https://en.wikipedia.org/wiki/Sky_Rocket"},
  'cannibal': {"description":"Cannibal is a steel roller coaster located at Lagoon Amusement Park in Farmington, Utah.  It opened with the tallest beyond-vertical drop in the world on July 2, 2015, and its drop angle of 116 degrees was the steepest in the United States for a brief time.  A large portion of the $22-million ride was built and designed in-house, a rare move for an amusement park.","wikiUrl":"https://en.wikipedia.org/wiki/Cannibal_(roller_coaster)"},
  'scorpion': {"description":"Scorpion was a steel roller coaster at Busch Gardens Tampa Bay in Tampa, Florida.  Designed by Anton Schwarzkopf and manufactured by Werner Stengel, it opened on May 16, 1980, as the second roller coaster at the park.  The roller coaster was added as part of the newly constructed Timbuktu section during the second-phased opening, being surrounded by the Congo and Nairobi sections.","wikiUrl":"https://en.wikipedia.org/wiki/Scorpion_(roller_coaster)"},
  'takabisha': {"description":"Takabisha (高飛車) is a Gerstlauer Euro-Fighter steel roller coaster located at Fuji-Q Highland in Fujiyoshida, Yamanashi, Japan.  It opened on 16 July 2011, and is known for having a drop angle of 121°.  It was the steepest coaster in the world before it was overtaken in 2019 by TMNT Shellraiser at American Dream in New Jersey.","wikiUrl":"https://en.wikipedia.org/wiki/Takabisha"},
  'grizzly': {"description":"Grizzly is a wooden roller coaster at Kings Dominion in Doswell, Virginia.  The grounds of the ride are densely forested, with the intended thrills heightened from the illusion of inadequate clearance between the track and trees.  The attraction opened in 1982, and the double-figure-eight layout is based closely on the defunct Coney Island Wildcat.","wikiUrl":"https://en.wikipedia.org/wiki/Grizzly_(Kings_Dominion)","formerNames":["The Grizzly"]},
  'leap-the-dips': {"description":"Leap-The-Dips is a wooden roller coaster located at Lakemont Park near Altoona, Pennsylvania.  Built in 1902 by the Federal Construction Company and designed by E.  Joy Morris, it is the oldest standing roller coaster in the world and believed to be the last surviving side friction roller coaster of the figure-eight variety.","wikiUrl":"https://en.wikipedia.org/wiki/Leap-The-Dips"},
  'abyssus': {"description":"Abyssus is a steel launched roller coaster at Energylandia in Zator, Poland.  The coaster officially opened as the headlining attraction in the new Aqualantis park area on July 14, 2021, after its opening was delayed by over a year due to the impact of the COVID-19 pandemic.  Abyssus is a Shockwave model manufactured by Vekoma and represents Energylandia’s 17th roller coaster to date.","wikiUrl":"https://en.wikipedia.org/wiki/Abyssus"},
};
